import scala.collection.mutable

def solve(weights: Array[Long]): Long = {
    val n = weights.length
    val stack = mutable.Stack[Int]()
    val intervals = mutable.ListBuffer[(Int, Int)]()
    for (i <- 0 until n) {
        while (stack.nonEmpty && weights(stack.top) <= weights(i)) {
            stack.pop()
        }
        if (stack.nonEmpty) {
            val pge = stack.top
            intervals += ((pge, i))
        }
        stack.push(i)
    }
    val sorted = intervals.sortBy(_._2)
    var count = 0L
    var lastEnd = -1
    for ((start, end) <- sorted) {
        if (start > lastEnd) {
            count += 1
            lastEnd = end
        }
    }
    count
}
